from scipy.ndimage import gaussian_filter1dimport matplotlib.pyplot as pltdef find_active_regions(wavelength, opacity, threshold=0.1, smooth_sigma=70, show=False):    """    smooth_sigma: width of Gaussian kernel in pixels.    Increase it until regions merge to your liking.    """        if(show): plot(wavelength, opacity)        opacity_smooth = gaussian_filter1d(opacity, sigma=smooth_sigma)        mask = opacity_smooth >= threshold    regions = []    inside = False    for wl, active in zip(wavelength, mask):        if active and not inside:            start = wl            inside = True        elif not active and inside:            regions.append((start, wl))            inside = False    if inside:        regions.append((start, wavelength[-1]))            regions = merge_regions(regions, wavelength)        return regionsdef merge_regions(regions, wavelength, min_gap_nm=0.05):    """Merge regions separated by less than min_gap_nm."""    if not regions:        return regions    merged = [regions[0]]    for start, end in regions[1:]:        if start - merged[-1][1] < min_gap_nm:            merged[-1] = (merged[-1][0], end)  # extend previous region        else:            merged.append((start, end))    return mergeddef plot(wavelength, opacity):        print("Plotting...")    _, ax = plt.subplots(figsize=(12, 6))    ax.plot(wavelength, opacity)        ax.set_xlim(wavelength.min(), wavelength.max())    ax.set_ylim(opacity.min(), opacity.max())    ax.set_ylabel("Opacity")    ax.set_xlabel("Wavelength (μm)")    plt.show()    